from bisect import bisect_left
from typing import List

class Solution:
    def minAbsoluteDifference(self, nums: List[int], x: int) -> int:
        n = len(nums)
        sorted_list = []
        min_diff = float('inf')

        for i in range(n):
            # Check elements at least x indices apart
            if i - x >= 0:
                # Insert nums[i - x] into sorted_list
                insert_pos = bisect_left(sorted_list, nums[i - x])
                sorted_list.insert(insert_pos, nums[i - x])

            # Check if current nums[i] can form a valid pair with elements in sorted_list
            if sorted_list:
                # Find closest elements to nums[i]
                pos = bisect_left(sorted_list, nums[i])
                if pos < len(sorted_list):
                    min_diff = min(min_diff, abs(sorted_list[pos] - nums[i]))
                if pos > 0:
                    min_diff = min(min_diff, abs(sorted_list[pos - 1] - nums[i]))

        return min_diff
